#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

static bool is_temperature_rising(int current, int previous_valid);

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

bool is_temperature_rising(int current, int previous_valid)
{
    if (current < previous_valid) {
        return false;
    }
    // Temperature is rising or staying same - return true
    // If it's exactly equal, it's not "rising" but the task says "not rising" means holding
    return current > previous_valid;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };

    // Handle timeout case
    if (controller->has_valid_sensor && input.now_ms - controller->last_valid_sensor_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_off(controller);
        output.timed_out = true;
        return output;
    }

    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    // Handle malformed input - turn heater off
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.timed_out = true;  // Treat malformed as timeout
        return output;
    }

    // Process temperature input
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            // Turn heater on for low temperature
            controller_set_safe_off(controller);
            controller->heater_on = true;
            output.state = CONTROLLER_STATE_HEATING;
            output.state_name = "STATE HEATING";
            output.changed = true;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            // Turn heater off for high temperature
            controller_set_safe_off(controller);
            controller->heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = "STATE SAFE_OFF";
            output.changed = true;
        } else {
            // Temperature in range: 47 <= TEMP < 50, preserve previous safe actuator state (HOLDING)
            if (previous_heater_on != controller->heater_on) {
                output.state = CONTROLLER_STATE_HOLDING;
                output.state_name = "STATE HOLDING";
                output.changed = true;
            } else {
                // Already in holding, no change needed
            }
        }
    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_off(controller);
        output.timed_out = true;  // Treat sensor timeout as timeout
        return output;
    }

    // If we're in the holding state and temperature is rising, turn heater off early
    if (controller->state == CONTROLLER_STATE_HOLDING) {
        if (input.kind == CONTROLLER_INPUT_TEMPERATURE && 
            input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            controller_set_safe_off(controller);
            controller->heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = "STATE SAFE_OFF";
            output.changed = true;
        } else {
            // Still holding, no change needed
        }
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || 
                       (previous_state != controller->state) ||
                       (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

