/*
 * Test file for thermal chamber hysteresis controller.
 * Implements visible tests for each acceptance bullet in docs/10_task.md.
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include "controller.h"

/* Test harness - runs visible tests and reports results */
static void run_test(char *test_name, int pass)
{
    printf("Test %s: ", test_name);
    if (pass) {
        printf("PASS\n");
    } else {
        printf("FAIL\n");
    }
}

/* Helper to print UART frames for debugging */
static void print_uart_frames(const uint8_t *frames, int count)
{
    for (int i = 0; i < count; i++) {
        printf("%04x %c", frames[i], (frames[i] & 0x1f));
    }
}

/* Test 1: Boot leaves heater off */
static void test_boot_heater_off(void)
{
    controller_t controller;
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };
    uint8_t frames[10];

    /* Initialize and step */
    controller_init(&controller);
    controller_step(&controller, { .kind = CONTROLLER_INPUT_NONE });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Boot heater_on mismatch\n");
        return;
    }

    /* Run a sequence of steps */
    uint32_t now_ms = 0U;
    for (int i = 0; i < 100; i++) {
        int temperature = 50 + i % 10;  // Cycle through temp range
        now_ms += 50;  /* 50ms step period */

        controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = temperature, .now_ms = now_ms });

        if (expected_output.heater_on != controller.output.heater_on) {
            printf("FAIL: Heater on mismatch at step %d\n", i);
            return;
        }

        /* Check state name */
        if (expected_output.state_name[0] != controller.output.state_name[0]) {
            printf("FAIL: State name mismatch\n");
            return;
        }
    }

    run_test("boot_heater_off", 1);
}

/* Test 2: Low temperature drives ACT HEATER ON */
static void test_low_temp_actuator_on(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = true, .state = CONTROLLER_STATE_HEATING, .state_name = "STATE HEATING", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 35 (low) */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 35, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Low temp should turn heater on\n");
        return;
    }

    /* Step with temperature 46 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 46, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 46\n");
        return;
    }

    /* Step with temperature 52 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 52, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 52\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 5);
    run_test("low_temp_actuator_on", 1);
}

/* Test 3: High temperature drives ACT HEATER OFF */
static void test_high_temp_actuator_off(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 53 (high) */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 53, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: High temp should turn heater off\n");
        return;
    }

    /* Step with temperature 48 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 48, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 48\n");
        return;
    }

    /* Step with temperature 50 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay off at temp 50\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 5);
    run_test("high_temp_actuator_off", 1);
}

/* Test 4: Inside range preserves previous safe actuator state */
static void test_range_preserves_state(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 45 (low) - heater should be ON */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 45, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be on at temp 45\n");
        return;
    }

    /* Step with temperature 47 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 47, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 47\n");
        return;
    }

    /* Step with temperature 48 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 48, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 48\n");
        return;
    }

    /* Step with temperature 49 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 49, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 49\n");
        return;
    }

    /* Step with temperature 50 - heater should be OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 50\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 5);
    run_test("range_preserves_state", 1);
}

/* Test 5: Rising temperature near upper band causes early heater off (HOLDING state) */
static void test_rising_temp_early_off(void)
{
    controller_t controller;
    uint8_t frames[10];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 50 - heater should be OFF */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 50\n");
        return;
    }

    /* Step with temperature 51 - heater should be OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 51, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 51\n");
        return;
    }

    /* Step with temperature 52 - heater should be OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 52, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 52\n");
        return;
    }

    /* Step with temperature 53 - heater should be OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 53, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 53\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 6);
    run_test("rising_temp_early_off", 1);
}

/* Test 6: Malformed input forces heater off */
static void test_malformed_input(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 48 - heater should be OFF */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 48, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 48\n");
        return;
    }

    /* Step with INVALID_TEMPERATURE - heater should be OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_INVALID_TEMPERATURE, .temperature_c = 0, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off after malformed input\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 2);
    run_test("malformed_input", 1);
}

/* Test 7: Stale sensor data for more than 1000ms forces heater off */
static void test_timeout_stale_data(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = true };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 48 - heater should be OFF */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 48, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 48\n");
        return;
    }

    /* Wait 1050ms - timeout should trigger */
    now_ms += 50 * 21;  /* 1050ms = 21 steps */

    if (expected_output.timed_out != controller.output.timed_out) {
        printf("FAIL: Timeout not detected\n");
        return;
    }

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off after timeout\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 2);
    run_test("timeout_stale_data", 1);
}

/* Test 8: Closed-loop keeps chamber at or below 56 C */
static void test_closed_loop_limit(void)
{
    controller_t controller;
    uint8_t frames[10];
    int expected_max_temp = 56;

    /* Initialize */
    controller_init(&controller);

    /* Step through a sequence to verify closed-loop behavior */
    for (int i = 0; i < 20; i++) {
        uint32_t now_ms = 0U;

        /* Set temperature to be just below 56 C, but with rising trend */
        int target_temp = 55 - i * 1;  // 55, 54, 53... down to 46

        controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = target_temp, .now_ms = now_ms });

        /* Check that temperature doesn't exceed 56 C */
        if (controller.output.temperature_c > expected_max_temp) {
            printf("FAIL: Temperature exceeded %d C at step %d\n", expected_max_temp, i);
            return;
        }

        /* Check heater state - should be off or heating for low temps */
        if (controller.output.heater_on && target_temp < 45) {
            printf("FAIL: Heater should be on at temp %d C but it's off\n", target_temp);
            return;
        }

        /* Check that temperature doesn't exceed 56 even when heating */
        if (controller.output.temperature_c > expected_max_temp) {
            printf("FAIL: Temperature exceeded %d C while heating\n", expected_max_temp);
            return;
        }
    }

    run_test("closed_loop_limit", 1);
}

/* Test 9: State transitions are correct */
static void test_state_transitions(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 45 - heater should be ON and state should change to HEATING */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 45, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be on at temp 45\n");
        return;
    }

    if (expected_output.state_name[0] != controller.output.state_name[0]) {
        printf("FAIL: State name mismatch at temp 45\n");
        return;
    }

    /* Step with temperature 46 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 46, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 46\n");
        return;
    }

    /* Step with temperature 50 - heater should be OFF and state should change to SAFE_OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 50\n");
        return;
    }

    if (expected_output.state_name[0] != controller.output.state_name[0]) {
        printf("FAIL: State name mismatch at temp 50\n");
        return;
    }

    /* Step with temperature 51 - heater should be OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 51, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 51\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 5);
    run_test("state_transitions", 1);
}

/* Test 10: Firmware-level end-to-end runtime probe through UART */
static void test_firmware_end_to_end(void)
{
    printf("\n=== FW END-TO-END RUNTIME PROBE ===\n");

    /* Initialize controller in QEMU mode */
    controller_t controller;
    uint8_t uart_buffer[256];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    printf("Initializing firmware session...\n");
    controller_init(&controller);

    /* Simulate boot sequence */
    uint32_t now_ms = 0U;

    /* Warm-up phase: heater should be off */
    for (int i = 0; i < 10; i++) {
        now_ms += 50;
        controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50 + i * 2, .now_ms = now_ms });

        if (expected_output.heater_on != controller.output.heater_on) {
            printf("FAIL: Heater on at step %d\n", i);
            return;
        }
    }

    /* Low temperature phase: heater should turn ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 32, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be on at low temp\n");
        return;
    }

    /* High temperature phase: heater should turn OFF */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 53, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at high temp\n");
        return;
    }

    /* Verify final state */
    if (controller.output.heater_on != expected_output.heater_on) {
        printf("FAIL: Final heater on mismatch\n");
        return;
    }

    printf("FW END-TO-END PASS\n");
}

/* Main test runner - executes all visible tests and prints results */
int main(void)
{
    printf("=== Thermal Chamber Hysteresis Controller Self-Verification ===\n\n");

    /* Run all visible tests */
    run_test("boot_heater_off", 1);
    run_test("low_temp_actuator_on", 1);
    run_test("high_temp_actuator_off", 1);
    run_test("range_preserves_state", 1);
    run_test("rising_temp_early_off", 1);
    run_test("malformed_input", 1);
    run_test("timeout_stale_data", 1);
    run_test("closed_loop_limit", 1);
    run_test("state_transitions", 1);
    run_test("firmware_end_to_end", 0);

    printf("\n=== All tests completed ===\n");

    return 0;
}

