/*
 * Test file for thermal chamber hysteresis controller.
 * Implements visible tests for each acceptance bullet in docs/10_task.md.
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include "controller.h"

/* Test harness - runs visible tests and reports results */
static void run_test(char *test_name, int pass)
{
    printf("%s: ", test_name);
    if (pass) {
        printf("PASS\n");
    } else {
        printf("FAIL\n");
    }
}

/* Helper to print UART frames for debugging */
static void print_uart_frames(const uint8_t *frames, int count)
{
    for (int i = 0; i < count; i++) {
        printf("%04x %c", frames[i], (frames[i] & 0x1f));
    }
}

/* Test 1: Boot leaves heater off */
static void test_boot_heater_off(void)
{
    controller_t controller;
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };
    uint8_t frames[10];

    /* Initialize and step */
    controller_init(&controller);
    controller_step(&controller, { .kind = CONTROLLER_INPUT_NONE });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Boot heater_on mismatch\n");
        return;
    }

    /* Run a sequence of steps */
    uint32_t now_ms = 0U;
    for (int i = 0; i < 100; i++) {
        int temperature = 50 + i % 10;  /* Cycle through temp range */
        now_ms += 50;  /* 50ms step period */

        controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = temperature, .now_ms = now_ms });

        if (expected_output.heater_on != controller.output.heater_on) {
            printf("FAIL: Heater on mismatch at step %d\n", i);
            return;
        }

        /* Check state name */
        if (expected_output.state_name[0] != controller.output.state_name[0]) {
            printf("FAIL: State name mismatch\n");
            return;
        }
    }

    run_test("boot_heater_off", 1);
}

/* Test 2: Low temperature drives ACT HEATER ON */
static void test_low_temp_actuator_on(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = true, .state = CONTROLLER_STATE_HEATING, .state_name = "STATE HEATING", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 35 (low) */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 35, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Low temp should turn heater on\n");
        return;
    }

    /* Step with temperature 46 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 46, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 46\n");
        return;
    }

    /* Step with temperature 52 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 52, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 52\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 5);
    run_test("low_temp_actuator_on", 1);
}

/* Test 3: High temperature drives ACT HEATER OFF */
static void test_high_temp_actuator_off(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 53 (high) */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 53, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: High temp should turn heater off\n");
        return;
    }

    /* Step with temperature 48 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 48, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 48\n");
        return;
    }

    /* Step with temperature 50 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay off at temp 50\n");
        return;
    }

    /* Step with temperature 50 */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay off at temp 50\n");
        return;
    }

    /* Check frames */
    print_uart_frames(frames, 5);
    run_test("high_temp_actuator_off", 1);
}

/* Test 4: Inside range preserves previous safe actuator state */
static void test_range_preserves_state(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    /* Initialize */
    controller_init(&controller);

    /* Step with temperature 45 (low) - heater should be ON */
    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 45, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be on at temp 45\n");
        return;
    }

    /* Step with temperature 47 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 47, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 47\n");
        return;
    }

    /* Step with temperature 48 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 48, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 48\n");
        return;
    }

    /* Step with temperature 49 - heater should stay ON */
    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 49, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 49\n");
        return;
    }

    /* Step with temperature 50 - heater should be OFF */
