    }

    print_uart_frames(frames, 2);
    run_test("timeout_stale_data", 1);
}

static void test_closed_loop_limit(void)
{
    controller_t controller;
    uint8_t frames[10];
    int expected_max_temp = 56;

    controller_init(&controller);

    for (int i = 0; i < 20; i++) {
        uint32_t now_ms = 0U;

        int target_temp = 55 - i * 1;

        controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = target_temp, .now_ms = now_ms });

        if (controller.output.temperature_c > expected_max_temp) {
            printf("FAIL: Temperature exceeded %d C at step %d\n", expected_max_temp, i);
            return;
        }

        if (controller.output.heater_on && target_temp < 45) {
            printf("FAIL: Heater should be on at temp %d C but it's off\n", target_temp);
            return;
        }

        if (controller.output.temperature_c > expected_max_temp) {
            printf("FAIL: Temperature exceeded %d C while heating\n", expected_max_temp);
            return;
        }
    }

    run_test("closed_loop_limit", 1);
}

static void test_state_transitions(void)
{
    controller_t controller;
    uint8_t frames[5];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    controller_init(&controller);

    uint32_t now_ms = 0U;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 45, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be on at temp 45\n");
        return;
    }

    if (expected_output.state_name[0] != controller.output.state_name[0]) {
        printf("FAIL: State name mismatch at temp 45\n");
        return;
    }

    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 46, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should stay on at temp 46\n");
        return;
    }

    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 50\n");
        return;
    }

    if (expected_output.state_name[0] != controller.output.state_name[0]) {
        printf("FAIL: State name mismatch at temp 50\n");
        return;
    }

    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 51, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at temp 51\n");
        return;
    }

    print_uart_frames(frames, 5);
    run_test("state_transitions", 1);
}

static void test_firmware_end_to_end(void)
{
    printf("\n=== FW END-TO-END RUNTIME PROBE ===\n");

    controller_t controller;
    uint8_t uart_buffer[256];
    int expected_output = { .heater_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .state_name = "STATE SAFE_OFF", .changed = false, .timed_out = false };

    printf("Initializing firmware session...\n");
    controller_init(&controller);

    uint32_t now_ms = 0U;

    for (int i = 0; i < 10; i++) {
        now_ms += 50;
        controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 50 + i * 2, .now_ms = now_ms });

        if (expected_output.heater_on != controller.output.heater_on) {
            printf("FAIL: Heater on at step %d\n", i);
            return;
        }
    }

    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 32, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be on at low temp\n");
        return;
    }

    now_ms += 50;
    controller_step(&controller, { .kind = CONTROLLER_INPUT_TEMPERATURE, .temperature_c = 53, .now_ms = now_ms });

    if (expected_output.heater_on != controller.output.heater_on) {
        printf("FAIL: Heater should be off at high temp\n");
        return;
    }

    if (controller.output.heater_on != expected_output.heater_on) {
        printf("FAIL: Final heater on mismatch\n");
        return;
    }

    printf("FW END-TO-END PASS\n");
}

